#include <bits/stdc++.h>
using namespace std;

int n, s, a, b, l, ans = 0;

struct Apple {
    int x, y;
} apple[5005];

bool cmp(Apple a, Apple b) {
    return a.y < b.y;
}

int main() {
    cin >> n >> s >> a >> b;
    l = a + b;
    for (int i = 0; i < n; i++) {
        cin >> apple[i].x >> apple[i].y;
    }
    sort(apple, apple + n, cmp);
    for (int i = 0; i < n; i++) {
        if (apple[i].x > l) {
            continue;
        }
        if (s < 0) {
            break;
        }
        s -= apple[i].y;
        ans++;
    }
    if (s < 0) ans--;
    cout << ans;
    return 0;
}
